1	// claim-office.ts
2	
3	export type Item = { type: string };
4	
5	export type QuoteInput = {
6	  items: Item[];
7	  customerYears: number;
8	  previousContracts: number;
9	};
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	function basePremiumFor(item: Item): number {
21	  return BASE_PREMIUM_BY_TYPE[item.type];
22	}
23	
24	export function quote(input: QuoteInput): number {
25	  const itemsBasePremium = input.items.reduce(
26	    (sum, item) => sum + basePremiumFor(item),
27	    0,
28	  );
29	  return itemsBasePremium + PROCESSING_FEE;
30	}
